diff --git a/packages/ui/src/engine/pixel-characters.ts b/packages/ui/src/engine/pixel-characters.ts
index 1234567..89abcde 100644
--- a/packages/ui/src/engine/pixel-characters.ts
+++ b/packages/ui/src/engine/pixel-characters.ts
@@ -700,6 +700,70 @@
+// Draw visual sound indicators near furniture, animated over 4 frames
+// ctx: CanvasRenderingContext2D
+// x, y: top-left position to draw indicator
+// type: 'forge' | 'scribe' | 'healing' | 'watchtower'
+// frame: 0..3 animation frame
+export function drawSoundIndicator(ctx: CanvasRenderingContext2D, x: number, y: number, type: string, frame: number) {
+  ctx.save();
+  ctx.translate(x, y);
+  ctx.lineCap = 'round';
+  ctx.lineJoin = 'round';
+  switch(type) {
+    case 'forge': {
+      // Orange impact lines radiating outward, small 10x10 px
+      // 4 frames: lines rotate and fade
+      const center = 5;
+      const maxLength = 6;
+      const alpha = 1 - frame * 0.25;
+      ctx.strokeStyle = `rgba(255,140,0,${alpha.toFixed(2)})`; // dark orange
+      ctx.lineWidth = 1.5;
+      ctx.translate(center, center);
+      for(let i=0; i<4; i++) {
+        const angle = (Math.PI/2)*i + frame*0.2;
+        ctx.beginPath();
+        ctx.moveTo(0,0);
+        ctx.lineTo(Math.cos(angle)*maxLength, Math.sin(angle)*maxLength);
+        ctx.stroke();
+      }
+      break;
+    }
+    case 'scribe': {
+      // Musical note icons floating up, 8x12 px area
+      // 4 frames: note moves up and fades
+      const noteY = 12 - frame*3;
+      const alpha = 1 - frame*0.25;
+      ctx.fillStyle = `rgba(0,0,0,${alpha.toFixed(2)})`;
+      ctx.beginPath();
+      // Draw simple eighth note shape
+      // note head (circle)
+      ctx.ellipse(6, noteY, 3, 4, 0, 0, Math.PI*2);
+      ctx.fill();
+      // stem
+      ctx.fillRect(8, noteY - 10, 1.5, 8);
+      // flag
+      ctx.beginPath();
+      ctx.moveTo(9.5, noteY - 10);
+      ctx.quadraticCurveTo(12, noteY - 8, 9.5, noteY - 6);
+      ctx.lineTo(9, noteY - 7);
+      ctx.quadraticCurveTo(11, noteY - 9, 9, noteY - 11);
+      ctx.closePath();
+      ctx.fill();
+      break;
+    }
+    case 'healing': {
+      // Concentric magic circles expanding, 12x12 px
+      // 4 frames: circles grow and fade
+      const center = 6;
+      ctx.lineWidth = 1;
+      for(let i=0; i<3; i++) {
+        const radius = 2 + frame*2 + i*3;
+        const alpha = Math.max(0, 1 - (frame + i*0.5)*0.4);
+        ctx.strokeStyle = `rgba(100,200,255,${alpha.toFixed(2)})`; // light blue
+        ctx.beginPath();
+        ctx.ellipse(center, center, radius, radius*0.6, 0, 0, Math.PI*2);
+        ctx.stroke();
+      }
+      break;
+    }
+    case 'watchtower': {
+      // Exclamation alert icons, 8x12 px
+      // 4 frames: icon pulses (scale and alpha)
+      const baseAlpha = 0.6 + 0.4 * Math.sin(frame * Math.PI / 2);
+      ctx.fillStyle = `rgba(255,0,0,${baseAlpha.toFixed(2)})`; // red
+      ctx.strokeStyle = `rgba(255,0,0,${baseAlpha.toFixed(2)})`;
+      ctx.lineWidth = 1.5;
+      ctx.translate(4, 2);
+      const scale = 1 + 0.1 * Math.sin(frame * Math.PI);
+      ctx.scale(scale, scale);
+      // Draw exclamation mark
+      ctx.beginPath();
+      ctx.rect(-1, 0, 2, 7);
+      ctx.fill();
+      ctx.beginPath();
+      ctx.ellipse(0, 9, 1.5, 1.5, 0, 0, Math.PI*2);
+      ctx.fill();
+      break;
+    }
+  }
+  ctx.restore();
+}
